function buildActivity(emp, adv, pay, projects = []) {
  const byId = Object.fromEntries(emp.map(e => [e.id, e]));
  const out = [];
  pay.forEach(r => out.push({
    ts: r.date,
    text: `Payroll run — ${MONTHS[r.month]} ${r.year}`,
    date: r.date,
    badge: 'PR',
    color: '#0F4F4A',
    amount: r.total,
    sign: -1
  }));
  adv.forEach(a => {
    const e = byId[a.employeeId];
    out.push({
      ts: a.date,
      text: `${a.kind === 'loan' ? 'Loan' : 'Advance'} to ${e ? e.name : '—'}`,
      date: a.date,
      badge: initials(e ? e.name : '?'),
      color: colorFor(e ? e.name : '?'),
      amount: a.amount,
      sign: 1
    });
  });
  projects.forEach(p => (p.assignments || []).forEach(a => {
    const e = byId[a.employeeId];
    (a.milestones || []).filter(m => m.paid).forEach(m => {
      out.push({
        ts: m.date,
        text: `${p.name} · ${m.label} → ${e ? e.name : '—'}`,
        date: m.date,
        badge: initials(e ? e.name : '?'),
        color: colorFor(e ? e.name : '?'),
        amount: m.amount,
        sign: -1
      });
    });
  }));
  return out.sort((a, b) => (b.ts || '').localeCompare(a.ts || ''));
}

